import requests
import os


class Tools:
    @staticmethod
    def run(
        query: str,
        model: str = "anthropic/claude-3.5-sonnet",
        max_tokens: int = 2048,
        temperature: float = 0.3,
    ) -> dict:
        """
        Send a research/academic query to a frontier LLM via OpenRouter.
        Returns reasoned answer (with optional citations if model supports).
        """
        api_key = os.environ.get("OPENROUTER_API_KEY")
        if not api_key:
            return {"error": "OPENROUTER_API_KEY not found"}

        url = "https://openrouter.ai/api/v1/chat/completions"

        headers = {
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json",
            "HTTP-Referer": "https://your-app.com",  # optional, helps with rate limits
            "X-Title": "OpenWebUI Research Tool",
        }

        payload = {
            "model": model,
            "messages": [
                {
                    "role": "system",
                    "content": "You are an expert academic researcher. Provide detailed, accurate, well-reasoned answers with references when possible.",
                },
                {"role": "user", "content": query},
            ],
            "max_tokens": max_tokens,
            "temperature": temperature,
        }

        try:
            r = requests.post(url, headers=headers, json=payload, timeout=90)
            r.raise_for_status()
            return r.json()
        except Exception as e:
            return {"error": str(e)}
